package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

class JsonElementTest {

  // Concrete subclass to test isJsonObject method
  static class JsonObject extends JsonElement {
    @Override
    public JsonElement deepCopy() {
      return new JsonObject();
    }
  }

  static class JsonArray extends JsonElement {
    @Override
    public JsonElement deepCopy() {
      return new JsonArray();
    }
  }

  static class JsonPrimitive extends JsonElement {
    @Override
    public JsonElement deepCopy() {
      return new JsonPrimitive();
    }
  }

  static class JsonNull extends JsonElement {
    @Override
    public JsonElement deepCopy() {
      return new JsonNull();
    }
  }

  @Test
  void testIsJsonObject_whenInstanceIsJsonObject_returnsTrue() {
    JsonElement jsonElement = new JsonObject();
    assertTrue(jsonElement.isJsonObject());
  }

  @Test
  void testIsJsonObject_whenInstanceIsJsonArray_returnsFalse() {
    JsonElement jsonElement = new JsonArray();
    assertFalse(jsonElement.isJsonObject());
  }

  @Test
  void testIsJsonObject_whenInstanceIsJsonPrimitive_returnsFalse() {
    JsonElement jsonElement = new JsonPrimitive();
    assertFalse(jsonElement.isJsonObject());
  }

  @Test
  void testIsJsonObject_whenInstanceIsJsonNull_returnsFalse() {
    JsonElement jsonElement = new JsonNull();
    assertFalse(jsonElement.isJsonObject());
  }
}
